/*
 * Test to verify timing advance power control compensation logic
 */

#include <stdio.h>
#include <stdint.h>

// Mock structures for testing
typedef struct {
    int ta_total;
    int ta_command;
    int tag_id;
    int frame;
    int slot;
    int ta_apply;
} NR_UL_TIME_ALIGNMENT_t;

typedef struct {
    NR_UL_TIME_ALIGNMENT_t ul_time_alignment;
    int ssb_rsrp_dBm;
} NR_UE_MAC_INST_t;

// Test the power control compensation logic
int16_t calculate_power_with_ta(NR_UE_MAC_INST_t *mac, int16_t base_power) {
    int16_t ta_compensation = 0;
    if (mac->ul_time_alignment.ta_apply) {
        /* Convert timing advance to power compensation (0.5 dB per TA unit as per spec) */
        ta_compensation = (int16_t)(mac->ul_time_alignment.ta_total * 5); /* 0.5 dB per unit = 5 * 0.1 dB */
    }
    return base_power + ta_compensation;
}

int main() {
    NR_UE_MAC_INST_t mac = {0};

    // Test case 1: No timing advance
    mac.ul_time_alignment.ta_apply = 0;
    mac.ul_time_alignment.ta_total = 0;
    int16_t base_power = 100; // 10.0 dBm in 0.1 dB units

    int16_t result1 = calculate_power_with_ta(&mac, base_power);
    printf("Test 1 - No TA: base_power=%d, result=%d (expected=%d)\n", base_power, result1, base_power);

    // Test case 2: Positive timing advance (TA = 10 units)
    mac.ul_time_alignment.ta_apply = 1;
    mac.ul_time_alignment.ta_total = 10;

    int16_t result2 = calculate_power_with_ta(&mac, base_power);
    printf("Test 2 - TA=10: base_power=%d, result=%d (expected=%d)\n", base_power, result2, base_power + 50);

    // Test case 3: Negative timing advance (TA = -5 units)
    mac.ul_time_alignment.ta_total = -5;

    int16_t result3 = calculate_power_with_ta(&mac, base_power);
    printf("Test 3 - TA=-5: base_power=%d, result=%d (expected=%d)\n", base_power, result3, base_power - 25);

    // Test case 4: Large timing advance (TA = 100 units)
    mac.ul_time_alignment.ta_total = 100;

    int16_t result4 = calculate_power_with_ta(&mac, base_power);
    printf("Test 4 - TA=100: base_power=%d, result=%d (expected=%d)\n", base_power, result4, base_power + 500);

    return 0;
}
